// Pure component — same props always produce the same JSX
function PriceTag({ amount, currency }) {
  const formatted = new Intl.NumberFormat('en-US', {
    style: 'currency', currency,
  }).format(amount);
  return <span className="price">{formatted}</span>;
}
// Safe to call 100 times — always same output, no external changes

// ✗ Side effect during render — dangerous
function UserCard({ userId }) {
  fetch(`/api/users/${userId}`).then(setUser); // fires on EVERY render
  return <div>{user?.name}</div>;
}

// ✓ Side effect after render — correct
function UserCard({ userId }) {
  const [user, setUser] = useState(null);
  useEffect(() => {
    fetch(`/api/users/${userId}`).then(r => r.json()).then(setUser);
  }, [userId]);
  return <div>{user?.name}</div>;
}

useEffect(() => {
  document.title = `${unread} unread messages`;
}, [unread]);

useEffect(() => {
  inputRef.current?.focus();
}, []);

useEffect(() => {
  const chart = new Chart(canvasRef.current, { type: 'bar', data });
  return () => chart.destroy();
}, [data]);

useEffect(() => {
  const controller = new AbortController();
  fetch(`/api/posts/${postId}`, { signal: controller.signal })
    .then(r => r.json())
    .then(setPost)
    .catch(err => { if (err.name !== 'AbortError') setError(err); });
  return () => controller.abort();
}, [postId]);

useEffect(() => {
  const id = setInterval(() => setSeconds(s => s + 1), 1000);
  return () => clearInterval(id);
}, []);

useEffect(() => {
  const handler = (e) => setKey(e.key);
  window.addEventListener('keydown', handler);
  return () => window.removeEventListener('keydown', handler);
}, []);

useEffect(() => {
  const sub = store.subscribe(() => setState(store.getState()));
  return () => sub.unsubscribe();
}, []);

function OrderSummary({ items, discount }) {
  // Pure — safe in render body
  const subtotal = items.reduce((sum, i) => sum + i.price * i.qty, 0);
  const total = subtotal * (1 - discount / 100) * 1.1;
  const sorted = [...items].sort((a, b) => a.name.localeCompare(b.name));
  return (
    <div>
      {sorted.map(i => <LineItem key={i.id} item={i} />)}
      <Total value={total} />
    </div>
  );
}

// Execution order per render:
// 1. Component function called (render phase)
// 2. React computes virtual DOM diff
// 3. React mutates the real DOM (commit phase)
// 4. Browser paints    ← useLayoutEffect fires here (before paint)
// 5. useEffect fires   ← after paint, asynchronous

useLayoutEffect(() => {
  // Sync measurement before paint — avoids flicker
  const { height } = ref.current.getBoundingClientRect();
  setHeight(height);
}, []);

// StrictMode: render body called twice per mount
function Bad() {
  fetch('/api/data'); // fires TWICE per mount in StrictMode — bug surfaces early
  return <div />;
}

// useEffect also runs twice in StrictMode (mount → cleanup → mount)
// verifies cleanup function correctly undoes the effect:
useEffect(() => {
  const sub = subscribe();
  return () => unsubscribe(sub); // called between the two mounts
}, []);

useEffect(() => {
  const controller = new AbortController();
  const ws = new WebSocket(url);
  ws.onmessage = (e) => setMessages(m => [...m, JSON.parse(e.data)]);
  return () => {
    controller.abort();
    ws.close();
  };
}, [url]);

// ✗ useEffect for a user action — roundabout
function Form() {
  const [submitted, setSubmitted] = useState(false);
  useEffect(() => {
    if (submitted) postToApi(data);
  }, [submitted]);
  return <button onClick={() => setSubmitted(true)}>Submit</button>;
}

// ✓ User actions in event handlers
function Form() {
  const handleSubmit = async () => {
    await postToApi(data);
    setSuccess(true);
  };
  return <button onClick={handleSubmit}>Submit</button>;
}

// React lifecycle per render:
//
//  ┌─────────────────────────────────────────────────────────┐
//  │  RENDER PHASE (pure)                                    │
//  │  1. React calls component function                      │
//  │  2. Reconciles virtual DOM diff                        │
//  │  3. Schedules DOM mutations                            │
//  └─────────────────────────────────────────────────────────┘
//                         │
//  ┌─────────────────────────────────────────────────────────┐
//  │  COMMIT PHASE                                           │
//  │  4. Applies DOM mutations                              │
//  │  5. Runs layout effects (useLayoutEffect)              │
//  │  6. Runs passive effects (useEffect) ← your code here  │
//  └─────────────────────────────────────────────────────────┘

function Profile({ userId }) {
  // Render phase: purely computes the virtual DOM
  const displayName = formatName(userId); // ✓ pure calc

  useEffect(() => {
    // Commit phase (post-paint): safe to run the side effect
    fetch(`/api/users/${userId}/presence`).then(...);
  }, [userId]);

  return <span>{displayName}</span>;
}

// ✗ Fetches on every render — infinite loop if setData triggers re-render
function UserList() {
  const [data, setData] = useState(null);
  fetch('/api/users').then(r => r.json()).then(setData); // ← in render!
  return <ul>{data?.map(u => <li key={u.id}>{u.name}</li>)}</ul>;
}

// ✓ Correct — move the fetch into an effect
function UserList() {
  const [data, setData] = useState(null);
  useEffect(() => {
    fetch('/api/users').then(r => r.json()).then(setData);
  }, []); // empty deps — run once on mount
  return <ul>{data?.map(u => <li key={u.id}>{u.name}</li>)}</ul>;
}

// ✗ A new interval is registered on every render, never cleared
function Clock() {
  const [time, setTime] = useState(Date.now());
  setInterval(() => setTime(Date.now()), 1000); // ← in render!
  return <p>{new Date(time).toLocaleTimeString()}</p>;
}

// ✓ Correct — register once, clean up on unmount
function Clock() {
  const [time, setTime] = useState(Date.now());
  useEffect(() => {
    const id = setInterval(() => setTime(Date.now()), 1000);
    return () => clearInterval(id); // cleanup
  }, []);
  return <p>{new Date(time).toLocaleTimeString()}</p>;
}

// useLayoutEffect — runs before the browser paints
function Tooltip({ anchor }) {
  const ref = useRef(null);
  useLayoutEffect(() => {
    // Safe: DOM is updated, browser hasn't painted yet
    const rect = anchor.getBoundingClientRect();
    ref.current.style.top = `${rect.bottom + 8}px`;
    ref.current.style.left = `${rect.left}px`;
  }, [anchor]);
  return <div ref={ref} className="tooltip" />;
}

// useEffect — runs after paint; DOM measurement would show stale layout
function Analytics({ page }) {
  useEffect(() => {
    trackPageView(page); // No DOM measurement needed — defer to after paint
  }, [page]);
}

// Resilient data-fetch effect
useEffect(() => {
  let cancelled = false;
  async function load() {
    const data = await fetchUser(userId);
    if (!cancelled) setUser(data); // ignore result if effect already cleaned up
  }
  load();
  return () => { cancelled = true; };
}, [userId]);

// In strict mode, React runs:
//   mount → run effect → cleanup (cancelled = true) → re-mount → run effect again
// The first fetch result is discarded; only the second `setUser` call fires.
